import './App.css';

const columns = [
  {
    title: 'Backlog',
    items: [
      'Weekly event-driven options prep',
      'Build rolling Wellness Initiative action plan',
      'Solar completion tracker + blocker map',
      'Prioritized 3D print queue for home + veterinary use',
      'Weekly family logistics snapshot',
      'Safe upgrade pipeline (sandbox + rollback required)',
      'Daily 6AM idea system validation (7-day reliability test)',
    ],
  },
  {
    title: 'Review Needed',
    items: [
      'Review topic operating mode update: all group messages treated as direct',
      'Review mobile bootstrap message and confirm final wording',
      'Review Kanban hosting approach decision (Hostinger FTP deployment)',
    ],
  },
  { title: 'To Do', items: [] },
  { title: 'In Progress', items: [] },
  { title: 'Blocked', items: [] },
  {
    title: 'Done',
    items: [
      'Created 8 Telegram project topics in COMMAND CENTER',
      'Generated full operating system bootstrap message',
      'Generated short mobile bootstrap version',
      'Built and deployed Kanban site to https://wellne.ss/kanban/',
      'Fixed starter React page issue by replacing App content',
      'Verified production URL + JS assets return HTTP 200',
    ],
  },
];

function App() {
  return (
    <div className="App">
      <header className="topbar">
        <h1>Command Center Kanban</h1>
        <p>Operating mode active • Execution only starts in In Progress</p>
      </header>

      <main className="board">
        {columns.map((column) => (
          <section key={column.title} className="column">
            <h2>{column.title}</h2>
            <div className="cards">
              {column.items.length === 0 ? (
                <div className="empty">No cards yet</div>
              ) : (
                column.items.map((card) => (
                  <article key={card} className="card">
                    {card}
                  </article>
                ))
              )}
            </div>
          </section>
        ))}
      </main>
    </div>
  );
}

export default App;
